import{_ as t,o as d,c as a,a3 as r}from"./chunks/framework.oxq6d-og.js";const f=JSON.parse('{"title":"Thread selection","description":"","frontmatter":{},"headers":[],"relativePath":"en/nthread/thread-selection.md","filePath":"en/nthread/thread-selection.md"}'),o={name:"en/nthread/thread-selection.md"};function s(n,e,i,c,h,l){return d(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="thread-selection" tabindex="-1">Thread selection <a class="header-anchor" href="#thread-selection" aria-label="Permalink to &quot;Thread selection&quot;">​</a></h1><p>NThread drives one target thread for its entire lifetime, so selection is a stability decision, not just a performance choice.</p><table tabindex="0"><thead><tr><th><code>idType</code></th><th>Meaning</th><th>Behavior</th></tr></thead><tbody><tr><td><code>thread</code></td><td>Thread ID</td><td>Uses that specific thread.</td></tr><tr><td><code>process</code></td><td>Process ID</td><td>Uses the process&#39;s first enumerable thread.</td></tr><tr><td><code>processAllThreadIds</code></td><td>Process ID</td><td>Races all candidates; the first successful redirection wins. This is the default.</td></tr></tbody></table><p>Avoid UI message-loop threads, loader/startup threads, long-running lock holders, dying threads, and the driving thread of a NHook memory accessor. A race winner is merely a thread that completed redirection; it is not proof that the target&#39;s semantics are safe.</p><p>Start with the default in a controlled process, log the winner through <code>.nthread.threadId</code>, and move to <code>idType: &#39;thread&#39;</code> only when you understand the target&#39;s threading model.</p>',5)])])}const m=t(o,[["render",s]]);export{f as __pageData,m as default};
